INSERT INTO `self_check_questions` (`id`, `self_check_id`, `question_text`, `image`, `question_type`, `points`, `options`, `correct_answer`, `explanation`, `metadata`, `media`, `order`, `part_index`, `created_at`, `updated_at`) VALUES (6,3,'It is an electronic device that resists, limits or opposes the amount of current in a circuit.',NULL,'multiple_choice',1,'[\"resistor\",\"capacitor\",\"diode\",\"none of the above\"]','0',NULL,NULL,NULL,1,NULL,'2026-03-26 19:42:00','2026-03-26 19:42:00'),(7,3,'A kind of resistor that can varies the resistance.',NULL,'multiple_choice',1,'[\"Fixed resistor\",\"Potentiometer\",\"Volume control\",\"Variable resistor\"]','3',NULL,NULL,NULL,2,NULL,'2026-03-26 19:42:00','2026-03-26 19:42:00'),(8,3,'A circuit with only one possible path that the electrical current may flow.',NULL,'multiple_choice',1,'[\"Parallel\",\"Series\",\"Series-Parallel\",\"none of the above\"]','1',NULL,NULL,NULL,3,NULL,'2026-03-26 19:42:00','2026-03-26 19:42:00'),(9,3,'The computation of accepted value of resistor\'s resistance from minimum to maximum.',NULL,'multiple_choice',1,'[\"decoding\",\"conversion\",\"Tolerance\",\"none of the above\"]','2',NULL,NULL,NULL,4,NULL,'2026-03-26 19:42:00','2026-03-26 19:42:00'),(10,3,'It states that an electrical circuit\'s current is directly proportional to its voltage, and inversely proportional to its resistance.',NULL,'multiple_choice',1,'[\"Farad law\",\"Ohm\'s law\",\"Volt\'s law\",\"none of the above\"]','1',NULL,NULL,NULL,5,NULL,'2026-03-26 19:42:00','2026-03-26 19:42:00'),(11,4,'Write and illustrate the resistor\'s color coding table in exact order. Include columns for: COLOR, DIGIT, MULTIPLIER, and TOLERANCE.',NULL,'essay',10,NULL,'[\"The table should include all colors (Black, Brown, Red, Orange, Yellow, Green, Blue, Violet, Grey, White, Gold, Silver, None) with their corresponding digit values, multipliers, and tolerance percentages.\"]',NULL,NULL,NULL,1,NULL,'2026-03-26 19:42:26','2026-03-26 19:42:26'),(12,5,'What is the resistance value for: Brown, Black, Red, Gold?',NULL,'short_answer',2,NULL,'[\"1000\",\"1k\",\"1k\\u03a9\",\"1000\\u03a9\",\"1 k\\u03a9\"]',NULL,NULL,NULL,1,NULL,'2026-03-26 19:42:47','2026-03-26 19:42:47'),(13,5,'What is the resistance value for: Green, Blue, Yellow, Gold?',NULL,'short_answer',2,NULL,'[\"560000\",\"560k\",\"560k\\u03a9\"]',NULL,NULL,NULL,2,NULL,'2026-03-26 19:42:47','2026-03-26 19:42:47'),(14,5,'What is the resistance value for: Violet, Red, Orange, Silver?',NULL,'short_answer',2,NULL,'[\"72000\",\"72k\",\"72k\\u03a9\"]',NULL,NULL,NULL,3,NULL,'2026-03-26 19:42:47','2026-03-26 19:42:47'),(15,5,'What is the resistance value for: Yellow, White, Gold, Gold?',NULL,'short_answer',2,NULL,'[\"4.9\",\"4.9\\u03a9\"]',NULL,NULL,NULL,4,NULL,'2026-03-26 19:42:47','2026-03-26 19:42:47'),(16,5,'What is the resistance value for: Orange, Orange, Brown, Gold?',NULL,'short_answer',2,NULL,'[\"330\",\"330\\u03a9\"]',NULL,NULL,NULL,5,NULL,'2026-03-26 19:42:47','2026-03-26 19:42:47'),(17,5,'What are the color bands for 680 Ω ± 5%?',NULL,'short_answer',2,NULL,'[\"Blue, Grey, Brown, Gold\",\"Blue Grey Brown Gold\"]',NULL,NULL,NULL,6,NULL,'2026-03-26 19:42:47','2026-03-26 19:42:47'),(18,5,'What are the color bands for 27 kΩ ± 10%?',NULL,'short_answer',2,NULL,'[\"Red, Violet, Orange, Silver\",\"Red Violet Orange Silver\"]',NULL,NULL,NULL,7,NULL,'2026-03-26 19:42:47','2026-03-26 19:42:47'),(19,5,'What are the color bands for 8.2 MΩ ± 5%?',NULL,'short_answer',2,NULL,'[\"Grey, Red, Green, Gold\",\"Gray, Red, Green, Gold\"]',NULL,NULL,NULL,8,NULL,'2026-03-26 19:42:47','2026-03-26 19:42:47'),(20,5,'What are the color bands for 4.7 kΩ ± 10%?',NULL,'short_answer',2,NULL,'[\"Yellow, Violet, Red, Silver\",\"Yellow Violet Red Silver\"]',NULL,NULL,NULL,9,NULL,'2026-03-26 19:42:47','2026-03-26 19:42:47'),(21,5,'What are the color bands for 82 Ω ± 5%?',NULL,'short_answer',2,NULL,'[\"Grey, Red, Black, Gold\",\"Gray, Red, Black, Gold\"]',NULL,NULL,NULL,10,NULL,'2026-03-26 19:42:47','2026-03-26 19:42:47'),(22,6,'Calculate the tolerance for: Red, Blue, Red, Gold. Provide the resistance value, minimum tolerance, and maximum tolerance.',NULL,'essay',5,NULL,'[\"Value: 2600\\u03a9 or 2.6k\\u03a9, Tolerance: \\u00b15%, Min: 2470\\u03a9, Max: 2730\\u03a9\"]',NULL,NULL,NULL,1,NULL,'2026-03-26 19:43:10','2026-03-26 19:43:10'),(23,6,'Calculate the tolerance for: Grey, Orange, Yellow, Gold. Provide the resistance value, minimum tolerance, and maximum tolerance.',NULL,'essay',5,NULL,'[\"Value: 830000\\u03a9 or 830k\\u03a9, Tolerance: \\u00b15%, Min: 788500\\u03a9, Max: 871500\\u03a9\"]',NULL,NULL,NULL,2,NULL,'2026-03-26 19:43:10','2026-03-26 19:43:10'),(24,6,'Calculate the tolerance for: White, Black, Brown, Gold. Provide the resistance value, minimum tolerance, and maximum tolerance.',NULL,'essay',5,NULL,'[\"Value: 900\\u03a9, Tolerance: \\u00b15%, Min: 855\\u03a9, Max: 945\\u03a9\"]',NULL,NULL,NULL,3,NULL,'2026-03-26 19:43:10','2026-03-26 19:43:10'),(25,6,'Calculate the tolerance for: Blue, Black, Gold, Gold. Provide the resistance value, minimum tolerance, and maximum tolerance.',NULL,'essay',5,NULL,'[\"Value: 6\\u03a9, Tolerance: \\u00b15%, Min: 5.7\\u03a9, Max: 6.3\\u03a9\"]',NULL,NULL,NULL,4,NULL,'2026-03-26 19:43:10','2026-03-26 19:43:10'),(26,6,'Calculate the tolerance for: Violet, Red, Gold, Gold. Provide the resistance value, minimum tolerance, and maximum tolerance.',NULL,'essay',5,NULL,'[\"Value: 7.2\\u03a9, Tolerance: \\u00b15%, Min: 6.84\\u03a9, Max: 7.56\\u03a9\"]',NULL,NULL,NULL,5,NULL,'2026-03-26 19:43:10','2026-03-26 19:43:10'),(27,6,'Calculate the tolerance for: Brown, Red, Red, Silver. Provide the resistance value, minimum tolerance, and maximum tolerance.',NULL,'essay',5,NULL,'[\"Value: 1200\\u03a9 or 1.2k\\u03a9, Tolerance: \\u00b110%, Min: 1080\\u03a9, Max: 1320\\u03a9\"]',NULL,NULL,NULL,6,NULL,'2026-03-26 19:43:10','2026-03-26 19:43:10'),(28,6,'Calculate the tolerance for: Yellow, Violet, Orange, Silver. Provide the resistance value, minimum tolerance, and maximum tolerance.',NULL,'essay',5,NULL,'[\"Value: 47000\\u03a9 or 47k\\u03a9, Tolerance: \\u00b110%, Min: 42300\\u03a9, Max: 51700\\u03a9\"]',NULL,NULL,NULL,7,NULL,'2026-03-26 19:43:10','2026-03-26 19:43:10'),(29,6,'Calculate the tolerance for: Orange, Orange, Red, Silver. Provide the resistance value, minimum tolerance, and maximum tolerance.',NULL,'essay',5,NULL,'[\"Value: 3300\\u03a9 or 3.3k\\u03a9, Tolerance: \\u00b110%, Min: 2970\\u03a9, Max: 3630\\u03a9\"]',NULL,NULL,NULL,8,NULL,'2026-03-26 19:43:10','2026-03-26 19:43:10'),(30,6,'Calculate the tolerance for: Green, Blue, Brown, Silver. Provide the resistance value, minimum tolerance, and maximum tolerance.',NULL,'essay',5,NULL,'[\"Value: 560\\u03a9, Tolerance: \\u00b110%, Min: 504\\u03a9, Max: 616\\u03a9\"]',NULL,NULL,NULL,9,NULL,'2026-03-26 19:43:10','2026-03-26 19:43:10'),(31,6,'Calculate the tolerance for: Red, Red, Green, Silver. Provide the resistance value, minimum tolerance, and maximum tolerance.',NULL,'essay',5,NULL,'[\"Value: 2200000\\u03a9 or 2.2M\\u03a9, Tolerance: \\u00b110%, Min: 1980000\\u03a9, Max: 2420000\\u03a9\"]',NULL,NULL,NULL,10,NULL,'2026-03-26 19:43:10','2026-03-26 19:43:10'),(32,7,'Give at least 4 kinds of diodes and illustrate the schematic symbol.',NULL,'essay',4,NULL,NULL,NULL,NULL,NULL,1,NULL,'2026-03-31 18:07:51','2026-03-31 18:07:51'),(33,7,'Give at least 4 kinds of capacitors.',NULL,'essay',4,NULL,NULL,NULL,NULL,NULL,2,NULL,'2026-03-31 18:07:51','2026-03-31 18:07:51'),(34,7,'Give 2 parts of Diode.',NULL,'essay',2,NULL,NULL,NULL,NULL,NULL,3,NULL,'2026-03-31 18:07:51','2026-03-31 18:07:51'),(35,8,'It is a semi conductor device that can be used for amplification, oscillation, rectification and switching',NULL,'multiple_choice',1,'[\"Transistor\",\"Capacitor\",\"Diode\",\"None of the above\"]','0',NULL,NULL,NULL,1,NULL,'2026-03-31 18:12:41','2026-03-31 18:12:41'),(36,8,'A type of IC with a rectangular housing and two parallel rows of electrical connecting pins',NULL,'multiple_choice',1,'[\"Linear IC\",\"Dual In-line Package (DIP) IC\",\"Surface Mounted Device (SMD) IC\",\"None of the above\"]','1',NULL,NULL,NULL,2,NULL,'2026-03-31 18:12:41','2026-03-31 18:12:41'),(37,8,'An electro-magnetic device that is commonly used for step down of voltage',NULL,'multiple_choice',1,'[\"Power supply\",\"Integrated circuit\",\"Transformer\",\"None of the above\"]','2',NULL,NULL,NULL,3,NULL,'2026-03-31 18:12:41','2026-03-31 18:12:41'),(38,8,'All types of modern electronic devices. They are integrated, meaning that they are made as a total circuit and housed in one enclosure',NULL,'multiple_choice',1,'[\"Power supply\",\"Integrated circuit\",\"Transistor\",\"None of the above\"]','1',NULL,NULL,NULL,4,NULL,'2026-03-31 18:12:41','2026-03-31 18:12:41'),(39,8,'It is a process of a transistor, that allows to move back and forth',NULL,'multiple_choice',1,'[\"Amplification\",\"Rectification\",\"Oscillation\",\"None of the above\"]','2',NULL,NULL,NULL,5,NULL,'2026-03-31 18:12:41','2026-03-31 18:12:41'),(40,8,'Give at least two (2) types of Integrated circuit and illustrate how it look like.',NULL,'essay',2,NULL,NULL,NULL,NULL,NULL,6,NULL,'2026-03-31 18:12:41','2026-03-31 18:12:41'),(41,8,'What are the three (3) parts of Transistor?',NULL,'essay',3,NULL,NULL,NULL,NULL,NULL,7,NULL,'2026-03-31 18:12:41','2026-03-31 18:12:41'),(42,8,'What are the three (3) parts of Transformer?',NULL,'essay',3,NULL,NULL,NULL,NULL,NULL,8,NULL,'2026-03-31 18:12:41','2026-03-31 18:12:41'),(43,8,'Give at least two (2) types of rectification process.',NULL,'essay',2,NULL,NULL,NULL,NULL,NULL,9,NULL,'2026-03-31 18:12:41','2026-03-31 18:12:41');
