INSERT INTO `task_sheets` (`id`, `information_sheet_id`, `task_number`, `title`, `description`, `instructions`, `image_path`, `file_path`, `original_filename`, `document_content`, `estimated_duration`, `difficulty_level`, `randomize_items`, `created_at`, `updated_at`, `deleted_at`) VALUES (2,3,'1.2.1','Task Sheet No. 1.2.1','Checking and Testing of Resistor\n\nPERFORMANCE CRITERIA - Checking and Testing of Resistor\n\nRating Scale:\n1 - Poor\n2 - Fair\n3 - Good\n4 - Satisfactory\n5 - Excellent\n\nCriteria:\n1. Observe and follow safety policies and procedures?\n2. Use proper personal protective equipment?\n3. Did I identify different kind of electronic components?\n4. Follow measuring and correct ranging of Multi-meter?\n5. I used tools and equipments properly?\n','Performance Objectives: To understand the value of color coded resistor, to maximize the use of Multi-meter and to identify the conditions of a resistor.',NULL,NULL,NULL,NULL,NULL,'beginner',0,'2026-03-26 19:43:50','2026-03-31 20:38:29',NULL),(3,4,'1.3.1','Checking and Testing of Capacitor','To understand the value of capacitor, to intensify the use of Multi-meter and to identify the conditions of a capacitor.\n\nPERFORMANCE CRITERIA - Checking and Testing of Capacitor\n\nRating Scale:\n1 - Poor\n2 - Fair\n3 - Good\n4 - Satisfactory\n5 - Excellent\n\nCriteria:\n1. Observe and follow safety policies and procedures?\n2. Use proper personal protective equipment?\n3. Did I identify different kind of electronic components?\n4. Follow measuring and correct ranging of Multi-meter?\n5. I used tools and equipments properly?\n','1. Check the value of capacitor\n2. Check the polarity of the terminal\n3. Using the suggested range in testing a capacitor\n4. Use the tester in Reverse bias\n5. Write down the parts, description (CL,CL,etc.), findings, the range use and the remarks if good or defective such as leaky, shorted or open.\n6. Submit to Trainer for checking',NULL,NULL,NULL,NULL,NULL,'beginner',0,'2026-03-31 18:08:37','2026-03-31 20:38:29',NULL),(4,4,'1.3.2','Checking and Testing of Diode','To understand the value of diode, to intensify the use of Multi-meter and to identify the conditions of a diode.\n\nPERFORMANCE CRITERIA - Checking and Testing of Diode\n\nRating Scale:\n1 - Poor\n2 - Fair\n3 - Good\n4 - Satisfactory\n5 - Excellent\n\nCriteria:\n1. Observe and follow safety policies and procedures?\n2. Use proper personal protective equipment?\n3. Did I identify different kind of electronic components?\n4. Follow measuring and correct ranging of Multi-meter?\n5. I used tools and equipments properly?\n','1. Check the type of diode\n2. Check the polarity of the terminal\n3. Using the multi-meter, check by performing both reverse and forward bias\n4. Write down the parts, description (D1,D2,etc.), findings, the range use and the remarks if good or defective such as leaky, shorted or open.\n5. Submit to Trainer for checking',NULL,NULL,NULL,NULL,NULL,'beginner',0,'2026-03-31 18:08:37','2026-03-31 20:38:29',NULL),(5,5,'1.4.1','Checking and Testing of Transistor','To understand the value of capacitor, to intensify the use of Multi-meter and to identify the conditions of a capacitor.\n\nPERFORMANCE CRITERIA - Checking and Testing of Transistor\n\nRating Scale:\n1 - Poor\n2 - Fair\n3 - Good\n4 - Satisfactory\n5 - Excellent\n\nCriteria:\n1. Observe and follow safety policies and procedures?\n2. Use proper personal protective equipment?\n3. Did I identify different kind of electronic components?\n4. Follow measuring and correct ranging of Multi-meter?\n5. I used tools and equipments properly?\n','1. Check the value of Transistor\n2. Using the suggested range in testing a terminal of Transistor in finding the base, emitter and collector\n3. Use the tester in both reverse and forward bias\n4. Write down the parts, description (Q1,Q2,etc.), findings, the range use and the remarks if good or defective such as leaky, shorted or open.\n5. Submit to Trainer for checking',NULL,NULL,NULL,NULL,NULL,'beginner',0,'2026-03-31 18:12:51','2026-03-31 20:38:29',NULL),(6,6,'1.5.1','Drawing and Testing of Inventory (Power Supply)','Test the given module and inventory.\n\nPERFORMANCE CRITERIA - Drawing and Testing of Inventory (Power Supply)\n\nRating Scale:\n1 - Poor\n2 - Fair\n3 - Good\n4 - Satisfactory\n5 - Excellent\n\nCriteria:\n1. Observe and follow safety policies and procedures?\n2. Use proper personal protective equipment?\n3. Did I identify different kind of electronic components?\n4. Follow measuring and correct ranging of Multi-meter?\n5. I used tools and equipments properly?\n6. Schematic diagram interpretation is correct?\n','1. Check the value of resistor and capacitor\n2. Use a Multi-tester in testing continuity\n3. Ask the Trainer for the procedures on how to test/check components\n4. Identify basic electronic components and note the description like: resistor, capacitors, diodes, transistor and ICs\n5. Write down the parts, description, qty, actual reading, the range and remarks if it is good or defective\n6. Submit to Trainer for checking',NULL,NULL,NULL,NULL,NULL,'beginner',0,'2026-03-31 19:40:57','2026-03-31 20:38:29',NULL),(7,6,'1.5.2','Checking and Testing of Inventory (Flip – Flop)','To intensify the use of Multi-meter and schematic components reading, to intensify soldering technique and schematics reading.\n\nPERFORMANCE CRITERIA - Checking and Testing of Inventory (Flip-Flop)\n\nRating Scale:\n1 - Poor\n2 - Fair\n3 - Good\n4 - Satisfactory\n5 - Excellent\n\nCriteria:\n1. Observe and follow safety policies and procedures?\n2. Use proper personal protective equipment?\n3. Did I identify different kind of electronic components?\n4. Follow measuring and correct ranging of Multi-meter?\n5. I used tools and equipments properly?\n6. Schematic diagram interpretation is correct?\n','1. Identify all parts and components\n2. Check the value of resistors\n3. Ask the Trainer if you do not know the procedure\n4. Identify the positive and negative of the given schematic circuit then supply DC current\n5. Write down the parts, description, qty, actual reading, the range and remarks if it is good or defective\n6. Submit to Trainer for checking',NULL,NULL,NULL,NULL,NULL,'beginner',0,'2026-03-31 19:40:57','2026-03-31 20:38:29',NULL),(8,7,'1.6.1','Soldering and De-soldering, Terminalizing and Connecting, Troubleshooting Process','Supply DC current, follow schematic diagram and solder it by assembling, terminalizing, troubleshooting process.\n\nPERFORMANCE CRITERIA - Soldering and De-soldering\n\nRating Scale:\n1 - Poor\n2 - Fair\n3 - Good\n4 - Satisfactory\n5 - Excellent\n\nCriteria:\n1. Observe and follow safety policies and procedures?\n2. Use proper personal protective equipment?\n3. Did I identify different kind of electronic components?\n4. Follow measuring and correct ranging of Multi-meter?\n5. I used tools and equipments properly?\n6. Soldering technique is correct?\n7. Solder joints are of good quality (shiny, smooth)?\n8. No cold solder joints or bridges?\n','1. Get MA001 schematic Diagram\n2. Submit raw materials\n3. Record parts, quantity, description, unit, actual reading, range, remarks',NULL,NULL,NULL,NULL,NULL,'beginner',0,'2026-03-31 19:51:39','2026-03-31 20:38:29',NULL),(9,7,'1.6.2','Assembly of Flip-Flop Circuit','Assembly of Flip-Flop circuit following the schematic diagram, with soldering and troubleshooting.\n\nPERFORMANCE CRITERIA - Assembly of Flip-Flop Circuit\n\nRating Scale:\n1 - Poor\n2 - Fair\n3 - Good\n4 - Satisfactory\n5 - Excellent\n\nCriteria:\n1. Observe and follow safety policies and procedures?\n2. Use proper personal protective equipment?\n3. Did I identify different kind of electronic components?\n4. Follow measuring and correct ranging of Multi-meter?\n5. I used tools and equipments properly?\n6. Soldering technique is correct?\n7. Solder joints are of good quality?\n8. Circuit functions properly after assembly?\n9. Troubleshooting process followed correctly?\n','1. Get raw materials (Ask Trainer first)\n2. Check the value of every component given\n3. Components needed:\n   - LED green and red (2 pcs parallel)\n   - 10k ohms resistor (2 pcs)\n   - BC 547 transistor (2 pcs)\n   - 470 ohms resistor (2 pcs parallel)\n   - 100 micro farad capacitor (2 pcs)\n   - Switch (1 pc)\n   - 9 volt battery (supply)\n4. Follow Schematic Diagram of Flip-Flop\n5. Use conventional method (non-assembled/non-troubleshoot circuit)',NULL,NULL,NULL,NULL,NULL,'beginner',0,'2026-03-31 19:51:39','2026-03-31 20:38:29',NULL);
