INSERT INTO `job_sheets` (`id`, `information_sheet_id`, `job_number`, `title`, `description`, `file_path`, `original_filename`, `document_content`, `procedures`, `performance_criteria`, `estimated_duration`, `difficulty_level`, `randomize_steps`, `created_at`, `updated_at`, `deleted_at`) VALUES (1,7,'1.6.1','Soldering and De-soldering, Terminalizing and Connecting, Troubleshooting Process','Test the given module and inventory, supply power.',NULL,NULL,NULL,'1. MA001 schematic - Test and verify\n2. MA002/Flip-Flop - Assembly and testing\n3. 1N4007(diode) - Testing procedures\n4. 12 Volt DC motor - Connection and testing','Performance Criteria Checklist:\n\nRating Scale:\n1 - Poor\n2 - Fair\n3 - Good\n4 - Satisfactory\n5 - Excellent\n\nCriteria to be evaluated:\n• Observe and follow safety policies and procedures?\n• Use proper personal protective equipment?\n• Did I identify different kind of electronic components?\n• Follow measuring and correct ranging of Multi-meter?\n• I used tools and equipments properly?\n• Soldering technique is correct and joints are good quality?\n• Circuit functions properly after assembly?',NULL,'beginner',0,'2026-03-31 19:51:39','2026-03-31 20:37:54',NULL);
